import{_ as t,c as o,b as a,a as l,d as n,e as i,w as c,r as p,o as r}from"./app-AvIGnZ-r.js";const u={};function d(m,s){const e=p("RouteLink");return r(),o("div",null,[s[7]||(s[7]=a("h1",{id:"async-flush",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#async-flush"},[a("span",null,"Async Flush")])],-1)),a("p",null,[s[1]||(s[1]=n("In the ",-1)),i(e,{to:"/guide/crud.html"},{default:c(()=>s[0]||(s[0]=[n("previous chapter",-1)])),_:1,__:[0]}),s[2]||(s[2]=n(", you learned how to add, update, and delete entities using the ",-1)),s[3]||(s[3]=a("code",null,"Flush()",-1)),s[4]||(s[4]=n(" method. ",-1)),s[5]||(s[5]=a("code",null,"Flush()",-1)),s[6]||(s[6]=n(" executes both MySQL and cache (Redis, local cache) queries synchronously. Redis operations usually take a few milliseconds, and local cache changes are almost instantaneous. However, SQL queries can take a significant amount of time, typically more than 100 milliseconds. In high-traffic applications, SQL queries often become a performance bottleneck.",-1))]),s[8]||(s[8]=l(`<p>To address this issue, FluxaORM provides a powerful feature that allows you to run all SQL queries asynchronously. Instead of executing SQL directly against MySQL, <code>FlushAsync()</code> publishes the SQL operations to a Redis Stream. Cache updates (Redis and local cache) and Redis Search index updates are applied immediately (optimistic update), so reads see consistent data right away. A separate consumer process then picks up the queued SQL operations and executes them against MySQL.</p><h2 id="registering-the-async-sql-stream" tabindex="-1"><a class="header-anchor" href="#registering-the-async-sql-stream"><span>Registering the Async SQL Stream</span></a></h2><p>Before using <code>FlushAsync()</code>, you must register the async SQL stream with a Redis pool. Use <code>RegisterAsyncSQLStream()</code> during registry setup:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;context&quot;</span></span>
<span class="line"></span>
<span class="line">    <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    registry <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRegistry</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    registry<span class="token punctuation">.</span><span class="token function">RegisterMySQL</span><span class="token punctuation">(</span><span class="token string">&quot;user:password@tcp(localhost:3306)/db&quot;</span><span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">)</span></span>
<span class="line">    registry<span class="token punctuation">.</span><span class="token function">RegisterRedis</span><span class="token punctuation">(</span><span class="token string">&quot;localhost:6379&quot;</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">)</span></span>
<span class="line">    registry<span class="token punctuation">.</span><span class="token function">RegisterAsyncSQLStream</span><span class="token punctuation">(</span>fluxaorm<span class="token punctuation">.</span>DefaultPoolCode<span class="token punctuation">)</span> <span class="token comment">// register the async stream on the default Redis pool</span></span>
<span class="line">    registry<span class="token punctuation">.</span><span class="token function">RegisterEntity</span><span class="token punctuation">(</span>UserEntity<span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    engine<span class="token punctuation">,</span> err <span class="token operator">:=</span> registry<span class="token punctuation">.</span><span class="token function">Validate</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token comment">// ...</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>If you have a default Redis pool registered and do not call <code>RegisterAsyncSQLStream()</code> explicitly, FluxaORM automatically registers the async SQL streams on the default pool during <code>Validate()</code>. However, it is recommended to register it explicitly for clarity.</p></div><h2 id="using-flushasync" tabindex="-1"><a class="header-anchor" href="#using-flushasync"><span>Using FlushAsync</span></a></h2><p>Once the stream is registered, use <code>FlushAsync()</code> instead of <code>Flush()</code> on the context:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">user <span class="token operator">:=</span> UserProvider<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetName</span><span class="token punctuation">(</span><span class="token string">&quot;Alice&quot;</span><span class="token punctuation">)</span></span>
<span class="line">user<span class="token punctuation">.</span><span class="token function">SetEmail</span><span class="token punctuation">(</span><span class="token string">&quot;alice@example.com&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">err <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">FlushAsync</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>When <code>FlushAsync()</code> is called, the following happens:</p><ol><li><strong>Redis cache and search indexes are updated immediately</strong> -- entity data is written to Redis cache and Redis Search hashes right away.</li><li><strong>SQL queries are serialized and published</strong> to the <code>_fluxa_async_sql</code> Redis Stream instead of being executed against MySQL.</li><li>The entity is marked as flushed and tracking is cleared.</li></ol><p>This means that reads using cached lookups (e.g., <code>GetByID</code>, <code>GetByIDs</code>, <code>GetByUniqueIndex</code>) will return updated data immediately, while SQL-based searches will not return updated data until the consumer processes the queued operations.</p><h2 id="consuming-async-queries" tabindex="-1"><a class="header-anchor" href="#consuming-async-queries"><span>Consuming Async Queries</span></a></h2><p>You must run a consumer to process the queued SQL operations. The consumer reads events from the Redis Stream and executes them against MySQL.</p><p>Use <code>ctx.GetAsyncSQLConsumer()</code> to obtain a consumer:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ctx <span class="token operator">:=</span> engine<span class="token punctuation">.</span><span class="token function">NewContext</span><span class="token punctuation">(</span>context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">consumer<span class="token punctuation">,</span> err <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">GetAsyncSQLConsumer</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Process up to 100 events, blocking for up to 1 second waiting for new events</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token punctuation">{</span></span>
<span class="line">    err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;transient error consuming async SQL: %v&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">        time<span class="token punctuation">.</span><span class="token function">Sleep</span><span class="token punctuation">(</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span> <span class="token comment">// back off and retry</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>Consume(count int, blockTime time.Duration)</code> method:</p><ul><li>Reads up to <code>count</code> events from the stream.</li><li>Blocks for up to <code>blockTime</code> waiting for new events if none are available.</li><li>Executes each SQL operation against the appropriate MySQL pool.</li><li>Acknowledges successfully processed events.</li></ul><h3 id="autoclaim-for-stale-events" tabindex="-1"><a class="header-anchor" href="#autoclaim-for-stale-events"><span>AutoClaim for Stale Events</span></a></h3><p>If a consumer crashes and leaves events in a pending state, you can use <code>AutoClaim()</code> to reclaim and process them:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Reclaim events that have been pending for more than 30 seconds</span></span>
<span class="line">err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">AutoClaim</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">30</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>This is useful for recovering from consumer failures without losing queued operations.</p><h2 id="understanding-cache-updates" tabindex="-1"><a class="header-anchor" href="#understanding-cache-updates"><span>Understanding Cache Updates</span></a></h2><p>When <code>FlushAsync()</code> is called, cache updates happen immediately but SQL execution is deferred. This affects which read operations return updated data before the consumer processes the SQL:</p><p><strong>Returns updated data immediately:</strong></p><ul><li><code>GetByID()</code> -- when the entity uses <code>redisCache</code> or <code>localCache</code></li><li><code>GetByIDs()</code> -- when the entity uses cache</li><li><code>GetByUniqueIndex()</code> -- unique indexes are always cached in Redis</li></ul><p><strong>Does NOT return updated data until consumed:</strong></p><ul><li><code>Search()</code>, <code>SearchOne()</code>, <code>SearchIDs()</code>, <code>SearchWithCount()</code>, <code>SearchIDsWithCount()</code> -- these query MySQL directly, so they will not see the new data until the consumer has executed the SQL.</li></ul><div class="hint-container warning"><p class="hint-container-title">Warning</p><p>Entities without any cache (<code>redisCache</code> or <code>localCache</code>) will not be available via <code>GetByID()</code> or <code>GetByIDs()</code> until the consumer processes the SQL operations.</p></div><h2 id="handling-errors" tabindex="-1"><a class="header-anchor" href="#handling-errors"><span>Handling Errors</span></a></h2><p>The consumer classifies MySQL errors into two categories:</p><h3 id="transient-errors" tabindex="-1"><a class="header-anchor" href="#transient-errors"><span>Transient Errors</span></a></h3><p>Transient errors are temporary problems that may succeed on retry. When a transient error occurs, <code>Consume()</code> returns the error and the event remains in the stream&#39;s pending list for reprocessing.</p><p>Examples of transient errors:</p><ul><li>Connection refused or timeout</li><li>Error 1040: Too many connections</li><li>Error 1213: Deadlock found when trying to get lock</li><li>Error 1031: Disk full</li></ul><p>When you encounter a transient error, you should log it, wait briefly, and retry:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;transient error: %v&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">    time<span class="token punctuation">.</span><span class="token function">Sleep</span><span class="token punctuation">(</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">)</span></span>
<span class="line">    <span class="token comment">// retry on next loop iteration</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="permanent-errors-dead-letter-stream" tabindex="-1"><a class="header-anchor" href="#permanent-errors-dead-letter-stream"><span>Permanent Errors (Dead-Letter Stream)</span></a></h3><p>Permanent errors are problems that will not succeed on retry no matter how many times the query is re-executed. When a permanent error occurs, the event is moved to the dead-letter stream (<code>_fluxa_async_sql_failed</code>) and acknowledged from the main stream so it does not block processing.</p><p>Examples of permanent errors:</p><ul><li>Error 1062: Duplicate entry (duplicate key)</li><li>Error 1146: Table doesn&#39;t exist</li><li>Error 1054: Unknown column</li><li>Error 1064: Syntax error</li><li>Error 1406: Data too long for column</li><li>Error 1048: Column cannot be null</li><li>Error 1452: Foreign key constraint fails</li></ul><p>The dead-letter stream retains the failed SQL operations along with their error messages. You should monitor this stream and manually resolve the issues:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// The dead-letter stream name is available as a constant:</span></span>
<span class="line"><span class="token comment">// fluxaorm.AsyncSQLDeadLetterStreamName = &quot;_fluxa_async_sql_failed&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="multi-query-transactions" tabindex="-1"><a class="header-anchor" href="#multi-query-transactions"><span>Multi-Query Transactions</span></a></h2><p>When a single <code>FlushAsync()</code> call produces multiple SQL queries for the same database pool (e.g., inserting an entity and updating related records), those queries are grouped into a single <code>AsyncSQLOperation</code>. The consumer executes multiple queries within a database transaction to ensure atomicity. Single-query operations are executed without a transaction for better performance.</p>`,44))])}const k=t(u,[["render",d]]),g=JSON.parse('{"path":"/guide/async_flush.html","title":"Async Flush","lang":"en-US","frontmatter":{},"git":{"updatedTime":1764852499000,"contributors":[{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":21,"url":"https://github.com/lukaszlato"}],"changelog":[{"hash":"df36d23b887f15b420ad01444a0ce0929319c86f","time":1764852499000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"bfc685f185295c4935fe51069bacb3c93ec9beda","time":1764664948000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"543b75a617cfdd17e7cf88ab1b077d0d76abe156","time":1763554211000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"05cde08df4727b7fe9fd5a4c0728ad8669b86d5d","time":1762258506000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"2b4ccf298dcae121a76ac0374b03ee57c2d64e69","time":1761666166000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"a257bec7fda5983880990cb548ead6fdbd42b40a","time":1761657446000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"130fb63693ed6069305040e49387333bbfada18f","time":1760516483000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"fluxaorm"},{"hash":"91d64256be036bf1a78ee006b85f8604baceedc4","time":1759837372000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"fluxaorm"},{"hash":"92ddda252d5fd171e1e77c1d46a26f3ab0ab2e59","time":1754686962000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"fluxaorm"},{"hash":"d8436b5413bd99b4037fecd6c95be27cef70e370","time":1753907096000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"418785133d03f0cf535b4b27cfe635a40f0633fd","time":1704805952000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"5316633b0dc665daa301a6e699143725dd32c02e","time":1704788183000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"316a31e0c87cadff2385ecc502474311a5584360","time":1703064516000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"ac3d25eaee3c8eafc547cc49add3d35e6ae61d2f","time":1701952793000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"dc83a53fef0ad36f67f056c7013fb24dcfc45970","time":1699365088000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"cec00bb528a21f7b1fd09751bcc9c9c023d4d37d","time":1699022416000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"f417f33f84e808614be26ba489ea45f9fa1c6601","time":1699015861000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"b7708e52b318ecd32cb6b4c3d2828d38a274982d","time":1699004652000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"b22274772a9a6c02b9e9c15eb7e3847062c4d189","time":1698936648000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"25b7935fb75cfa9d00853e3ed637e0e241606b5f","time":1698859941000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"},{"hash":"71b8c5842abce8f6a48a9b038788cf373dc93300","time":1698523854000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"restored ID field"}]},"filePathRelative":"guide/async_flush.md"}');export{k as comp,g as data};
